import os
import shutil
from zipfile import ZipFile
try:
    from py7zr import SevenZip
except ImportError:
    print("Py7zr is required for this script. Install with `pip install py7zr`")
    exit(1)

def backup_directory(path, format):
    if not os.path.exists(path):
        return False
    
    filename = path.split('/')[-1]
    if format == 'tar.gz':
        shutil.make_archive(filename, 'gztar', root_dir=path)
    elif format == 'tar.bz2':
        shutil.make_archive(filename, 'bztar', root_dir=path)
    elif format == 'zip':
        with ZipFile(f'{filename}.zip', 'w') as zip:
            for foldername, subfolders, filenames in os.walk(path):
                for filename in filenames:
                    zip.write(os.path.join(foldername, filename), 
                              os.path.relpath(os.path.join(foldername, filename), path))
    elif format == '7z':
        s = SevenZip()
        s.compress_dir(path, f'{filename}.7z')
    else:
        return False
    
    print(f"Backup for {path} completed successfully")
    return True